∀ {action : SKEFTHawking.SKDoubling.SKAction} {beta : Real}
  {kms_transform : SKEFTHawking.SKDoubling.SKFields → SKEFTHawking.SKDoubling.SKFields}
  {kms_transform_spec :
    ∀ (f : SKEFTHawking.SKDoubling.SKFields),
      And (Eq (kms_transform f).psi_r f.psi_r)
        (And (Eq (kms_transform f).psi_a (instHAdd.hAdd f.psi_a (instHMul.hMul beta f.dt_psi_r)))
          (And (Eq (kms_transform f).dt_psi_r f.dt_psi_r) (Eq (kms_transform f).dx_psi_r f.dx_psi_r)))}
  {invariance :
    ∀ (f : SKEFTHawking.SKDoubling.SKFields), Eq (action.lagrangian (kms_transform f)) (action.lagrangian f)}
  {kms_transform_1 : SKEFTHawking.SKDoubling.SKFields → SKEFTHawking.SKDoubling.SKFields}
  {kms_transform_spec_1 :
    ∀ (f : SKEFTHawking.SKDoubling.SKFields),
      And (Eq (kms_transform_1 f).psi_r f.psi_r)
        (And (Eq (kms_transform_1 f).psi_a (instHAdd.hAdd f.psi_a (instHMul.hMul beta f.dt_psi_r)))
          (And (Eq (kms_transform_1 f).dt_psi_r f.dt_psi_r) (Eq (kms_transform_1 f).dx_psi_r f.dx_psi_r)))}
  {invariance_1 :
    ∀ (f : SKEFTHawking.SKDoubling.SKFields), Eq (action.lagrangian (kms_transform_1 f)) (action.lagrangian f)},
  Eq { kms_transform := kms_transform, kms_transform_spec := kms_transform_spec, invariance := invariance }
      { kms_transform := kms_transform_1, kms_transform_spec := kms_transform_spec_1, invariance := invariance_1 } →
    Eq kms_transform kms_transform_1

∀ (coeffs : SKEFTHawking.DissipativeCoeffs) (beta : Real),
  Eq (SKEFTHawking.SKDoubling.firstOrderDissipativeAction coeffs beta)
    {
      lagrangian := fun fields =>
        have re_part :=
          instHAdd.hAdd
            (instHMul.hMul (instHMul.hMul coeffs.gamma_1 fields.psi_a)
              (instHSub.hSub fields.dtt_psi_r fields.dxx_psi_r))
            (instHMul.hMul (instHMul.hMul coeffs.gamma_2 fields.psi_a) fields.dtt_psi_r);
        have im_part :=
          instHAdd.hAdd (instHMul.hMul (instHDiv.hDiv coeffs.gamma_1 beta) (instHPow.hPow fields.psi_a 2))
            (instHMul.hMul (instHDiv.hDiv coeffs.gamma_2 beta) (instHPow.hPow fields.dt_psi_a 2));
        { fst := re_part, snd := im_part } }

