      { gamma_1 := gamma_1_1, gamma_1_nonneg := gamma_1_nonneg_1, gamma_2 := gamma_2_3,
        gamma_2_nonneg := gamma_2_nonneg_1, gamma_2_1 := gamma_2_1_1, gamma_2_2 := gamma_2_2_1, gamma_x := gamma_x_1,
        gamma_x_nonneg := gamma_x_nonneg_1 } →
    And (Eq gamma_1 gamma_1_1)
      (And (Eq gamma_2 gamma_2_3)
