∀ (coeffs : SKEFTHawking.SecondOrderSK.CombinedDissipativeCoeffs) (beta : Real),
  Eq (SKEFTHawking.SecondOrderSK.combinedDissipativeAction coeffs beta)
    {
      lagrangian := fun f =>
        have re1 :=
          instHAdd.hAdd (instHMul.hMul (instHMul.hMul coeffs.gamma_1 f.psi_a) (instHSub.hSub f.dtt_psi_r f.dxx_psi_r))
            (instHMul.hMul (instHMul.hMul coeffs.gamma_2 f.psi_a) f.dtt_psi_r);
        have re2 :=
          instHAdd.hAdd (instHMul.hMul (instHMul.hMul coeffs.gamma_2_1 f.psi_a) f.dxxx_psi_r)
            (instHMul.hMul (instHMul.hMul coeffs.gamma_2_2 f.psi_a) f.dttx_psi_r);
        have im1 :=
          instHAdd.hAdd (instHMul.hMul (instHDiv.hDiv coeffs.gamma_1 beta) (instHPow.hPow f.psi_a 2))
            (instHMul.hMul (instHDiv.hDiv coeffs.gamma_2 beta) (instHPow.hPow f.dt_psi_a 2));
        have im2 :=
          instHMul.hMul
            (instHMul.hMul (instHDiv.hDiv (instHAdd.hAdd coeffs.gamma_2_1 coeffs.gamma_2_2) beta) f.dt_psi_a)
            f.dx_psi_a;
        { fst := instHAdd.hAdd re1 re2, snd := instHAdd.hAdd im1 im2 } }

